// Build a rate-parity digest from the StayingAPI /v1/price-compare response.
// Input item: { data: PriceCompare, meta: SuccessMeta }. Flags OTAs priced below
// the computed median for this property + dates (a parity exception to fix).
const out = [];
for (const item of $input.all()) {
  const data = item.json.data || {};
  const meta = item.json.meta || {};
  const currency = data.currency || meta.currency || 'USD';
  const median = typeof data.median === 'number' ? data.median : null;
  const offers = (Array.isArray(data.offers) ? [...data.offers] : []).sort(
    (a, b) => (a.totalPrice ?? Infinity) - (b.totalPrice ?? Infinity),
  );
  const rows = offers.map((o) => {
    const delta =
      median != null && typeof o.totalPrice === 'number'
        ? Math.round((o.totalPrice - median) * 100) / 100
        : null;
    return {
      ota: o.ota,
      totalPrice: o.totalPrice ?? null,
      currency: o.currency || currency,
      url: o.url ?? null,
      deltaVsMedian: delta,
      belowMedian: delta != null && delta < 0,
    };
  });
  const exceptions = rows.filter((r) => r.belowMedian);
  const spread =
    offers.length >= 2
      ? Math.round(((offers[offers.length - 1].totalPrice ?? 0) - (offers[0].totalPrice ?? 0)) * 100) / 100
      : 0;
  const lines = rows.map(
    (r) =>
      `${r.belowMedian ? '⚠︎ ' : '  '}${r.ota}: ${r.totalPrice} ${r.currency}` +
      (r.deltaVsMedian != null ? ` (${r.deltaVsMedian >= 0 ? '+' : ''}${r.deltaVsMedian} vs median)` : '') +
      (r.url ? ` — ${r.url}` : ''),
  );
  const report =
    `Rate-parity check — ${data.property ?? 'your property'}\n` +
    `Stay: ${data.checkIn} → ${data.checkOut} (${currency})\n` +
    `Median ${median ?? 'n/a'} · spread ${spread} ${currency}\n\n` +
    (exceptions.length
      ? `${exceptions.length} OTA(s) below the median:\n`
      : `No OTA is below the median — parity looks healthy.\n`) +
    `${lines.join('\n')}\n\n` +
    `Credits charged: ${meta.creditsCharged ?? 0} · requestId ${meta.requestId ?? ''}`;
  out.push({
    json: {
      property: data.property ?? null,
      checkIn: data.checkIn ?? null,
      checkOut: data.checkOut ?? null,
      currency,
      median,
      spread,
      exceptionCount: exceptions.length,
      exceptions,
      offers: rows,
      report,
    },
  });
}
return out;
